// ag-ui-client.ts — consume an AG-UI SSE stream
export interface AGUIMessage {
  id:      string;
  role:    "assistant";
  text:    string;
  status:  "streaming" | "done";
}

export interface AGUIToolCall {
  id:      string;
  name:    string;
  args:    string;   // accumulated partial JSON string
  done:    boolean;
}

export interface AGUIState {
  runId:      string | null;
  status:     "idle" | "running" | "done" | "error";
  messages:   AGUIMessage[];
  toolCalls:  AGUIToolCall[];
  agentState: Record<string, unknown>;
  error:      string | null;
}

type Dispatch = React.Dispatch<React.SetStateAction<AGUIState>>;

export function connectAGUI(url: string, body: object, dispatch: Dispatch): () => void {
  const controller = new AbortController();

  (async () => {
    const res = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
      signal: controller.signal,
    });
    if (!res.ok || !res.body) return;

    const reader  = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer    = "";

    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      buffer += decoder.decode(value, { stream: true });

      for (const line of buffer.split("\n")) {
        if (!line.startsWith("data: ")) continue;
        const evt = JSON.parse(line.slice(6));
        dispatch(state => applyEvent(state, evt));
      }
      buffer = "";
    }
  })().catch(() => {});

  return () => controller.abort();
}

function applyEvent(state: AGUIState, evt: Record<string, unknown>): AGUIState {
  switch (evt.type) {
    case "RUN_STARTED":
      return { ...state, runId: evt.run_id as string, status: "running", error: null };

    case "TEXT_MESSAGE_START":
      return {
        ...state,
        messages: [...state.messages, { id: evt.message_id as string, role: "assistant", text: "", status: "streaming" }],
      };

    case "TEXT_MESSAGE_DELTA":
      return {
        ...state,
        messages: state.messages.map(m =>
          m.id === evt.message_id ? { ...m, text: m.text + (evt.delta as string) } : m
        ),
      };

    case "TEXT_MESSAGE_END":
      return {
        ...state,
        messages: state.messages.map(m =>
          m.id === evt.message_id ? { ...m, status: "done" } : m
        ),
      };

    case "TOOL_CALL_START":
      return {
        ...state,
        toolCalls: [...state.toolCalls, {
          id: evt.tool_call_id as string, name: evt.tool_name as string, args: "", done: false,
        }],
      };

    case "TOOL_CALL_ARGS_DELTA":
      return {
        ...state,
        toolCalls: state.toolCalls.map(tc =>
          tc.id === evt.tool_call_id ? { ...tc, args: tc.args + (evt.delta as string) } : tc
        ),
      };

    case "TOOL_CALL_END":
      return {
        ...state,
        toolCalls: state.toolCalls.map(tc =>
          tc.id === evt.tool_call_id ? { ...tc, done: true } : tc
        ),
      };

    case "STATE_SNAPSHOT":
      return { ...state, agentState: evt.state as Record<string, unknown> };

    case "STATE_DELTA": {
      // Apply JSON Patch ops (RFC 6902) to agentState
      // Use a library like fast-json-patch in practice:
      // import { applyPatch } from "fast-json-patch";
      // return { ...state, agentState: applyPatch(state.agentState, evt.ops).newDocument };
      return state;
    }

    case "RUN_FINISHED":
      return { ...state, status: "done" };

    case "RUN_ERROR":
      return { ...state, status: "error", error: evt.error as string };

    default:
      return state;
  }
}

import json
import jsonpatch   # pip install jsonpatch

def compute_state_delta(old_state: dict, new_state: dict) -> str:
    """Compute JSON Patch ops (RFC 6902) between two state snapshots."""
    patch = jsonpatch.make_patch(old_state, new_state)
    return patch.to_string()   # e.g. [{"op":"replace","path":"/status","value":"running"}]

# Server: emit STATE_DELTA instead of STATE_SNAPSHOT when changes are small
previous_state: dict = {}

def maybe_emit_state(current_state: dict, run_id: str) -> str:
    global previous_state
    if not previous_state:
        # First emission: always send snapshot
        previous_state = current_state
        return emit(AGUIEvent(
            type=AGUIEventType.STATE_SNAPSHOT,
            run_id=run_id,
            state=current_state,
        ))

    delta = compute_state_delta(previous_state, current_state)
    previous_state = current_state
    if delta == "[]":
        return ""   # no change
    return emit(AGUIEvent(
        type=AGUIEventType.STATE_DELTA,
        run_id=run_id,
        delta=delta,   # JSON Patch ops array as a JSON string
    ))

// useAGUI.ts — React hook that manages AG-UI state
import { useCallback, useReducer } from "react";
import { connectAGUI, AGUIState }  from "./ag-ui-client";

const INITIAL: AGUIState = {
  runId: null, status: "idle", messages: [], toolCalls: [], agentState: {}, error: null,
};

export function useAGUI(endpoint: string) {
  const [state, dispatch] = useReducer(
    (s: AGUIState, action: React.SetStateAction<AGUIState>) =>
      typeof action === "function" ? action(s) : action,
    INITIAL,
  );

  const run = useCallback(
    (messages: object[], tools: object[] = [], system = "") => {
      // Reset state before starting a new run
      dispatch({ ...INITIAL, status: "running" });
      const cleanup = connectAGUI(endpoint, { messages, tools, system }, dispatch);
      return cleanup;
    },
    [endpoint],
  );

  return { state, run };
}

// In a component:
// const { state, run } = useAGUI("/agent/run");
// <button onClick={() => run([{ role: "user", content: "Hello" }])}>Start</button>
