import pytest, json

def parse_events(raw: str) -> list[dict]:
    events = []
    for line in raw.splitlines():
        if line.startswith("data: "):
            events.append(json.loads(line[6:]))
    return events

@pytest.mark.asyncio
async def test_agui_stream_event_sequence(client_fixture):
    response = await client_fixture.post("/agent/run", json={
        "messages": [{"role":"user","content":"Say hello"}],
    })
    events  = parse_events(response.text)
    types   = [e["type"] for e in events]

    assert types[0]  == "RUN_STARTED"
    assert "TEXT_MESSAGE_START" in types
    assert "TEXT_MESSAGE_DELTA" in types
    assert "TEXT_MESSAGE_END"   in types
    assert types[-2] == "STATE_SNAPSHOT"
    assert types[-1] == "RUN_FINISHED"

@pytest.mark.asyncio
async def test_run_id_consistent(client_fixture):
    response = await client_fixture.post("/agent/run", json={
        "messages": [{"role":"user","content":"Hello"}],
    })
    events = parse_events(response.text)
    run_ids = {e.get("run_id") for e in events if "run_id" in e}
    assert len(run_ids) == 1    # all events share the same run_id
